script.text:

function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    tt_qd: '[tt_qd]:=[ty_gia_hd]==0?[tien]:[tien]/[ty_gia_hd]',
    tt_nt: '[tt_qd]:=[tien_nt]',
    tt: '[tt_qd]:=[tien]',
    tien: '[tien]:=[tien_nt]*[$ty_gia]',
    tien_tggs: '[tien]:=[tien_nt]*[ty_gia_ht2]',
&ScriptTaxGridDetailDeclareArray;
    t_tien_nt: ['t_tien_nt', 'tien_nt'],
    t_tien: ['t_tien', 'tien'],
    t_tt: '[t_tt]:=[t_tien]+[t_thue]',
    t_tt_nt: '[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_kh', 'ngay_lct', 'ma_dvcs', 'stt_rec'];
  udf$Detail$(g);
}
/* <flatten type="Javascript"> */
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
}

function onChange$GridVoucherDetail$InvoiceNumber(o) {o.grid.request(o, 'InvoiceNumber', 'InvoiceNumber', ['so_hd', 'stt_rec_tt'], o.grid.$h, true);}
/* </flatten> */
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name, v = f.getItemValue('loai_ct');
  switch (name) {
    case 'tien_nt':
      if (v != '2' || f.getItemValue('ma_nt') == f._baseCurrency) g.validExpression(o, [g.$a.tien, g.$a.thue_nt, g.$a.thue2, g.$a.tien_tt_nt, g.$a.tien_tt], [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_thue1_nt, g.$a.t_thue1], [g.$a.t_thue_nt, g.$a.t_thue, g.$a.t_tt_nt, g.$a.t_tt]);
        else g.validExpression(o, [g.$a.tien_tggs, g.$a.tien_tt_nt, g.$a.tien_tt], [g.$a.t_tien_nt2, g.$a.t_tien2], [g.$a.t_tt_nt, g.$a.t_tt]);
      if (v == 1) {
        set$GridVoucherDetail$Payment(o, g, f);
        g.live(o, 'tt_qd');
      }
      break;
    case 'tien':
      g.validExpression(o, [g.$a.thue2, g.$a.tien_tt], [g.$a.t_tien2, g.$a.t_thue1_nt, g.$a.t_thue1], [g.$a.t_thue_nt, g.$a.t_thue, g.$a.t_tt]);
      break;
&ScriptTaxGridDetailValid;
    case 'ty_gia_ht2':
      if (v == '2') g.validExpression(o, [g.$a.tien_tggs, g.$a.tien_tt_nt, g.$a.tien_tt], [g.$a.t_tien_nt, g.$a.t_tien], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm, v = $func.trim(f.getItem("loai_ct").value);
  switch (action) {&PaymentRequestScriptCheckGridAction;
    case 'AfterInsertRow':
      onchange$Item$(f.getItem('loai_ct'));
      break;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (v == '1') if (!g.validRowExpression('so_hd', '([so_hd] != "")')) break;
      if (v == '9') {&ScriptTaxGridDetailCheck;}
      if (v == '3') g.validRowExpression('ma_kh_i', '([ma_kh_i] != "")');
      break;
    case 'ImportData':
      if (f._action == 'View') break;
      if (f.getItemValue('loai_ct') != '3') {
        $message.show(f._language == 'v' ? 'Loại phiếu chi không hợp lệ.' : 'Invalid voucher type.', String.format('$find(\'{0}\').focus(\'loai_ct\');', f.get_id()));
        break;
      };
      g.showForm('CDDetailImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (f.getItemValue('loai_ct') == '3') break;
      if (!f.validFields('ma_kh, ngay_ct, loai_ct')) break;
      g.showForm('CDRequestFilter');
      break;
&PaymentRequestCopying;
    default:
      break;
  }
}
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'InvoiceNumber':
      g.setItemGridBehavior(o, [
        ['tk_no', result[0].Value, result[1].Value, false],
        ['ngay_hd', result[2].Value, null, false],
        ['ma_nt_i', result[3].Value, null, false],
        ['ty_gia_hd', result[4].Value, null, false],
        ['tien_hd_nt', result[5].Value, null, false],
        ['da_tt_nt', result[6].Value, null, false],
        ['cl_nt', result[7].Value, null, false],
        ['ma_vv', result[8].Value, null, false],
        ['ma_bp', result[9].Value, null, false],
        ['so_lsx', result[10].Value, null, false],
        ['ma_sp', result[11].Value, null, false],
        ['ma_hd', result[12].Value, null, false],
        ['ma_phi', result[13].Value, null, false],
        ['ma_ku', result[14].Value, null, false]
      ]);
      set$GridVoucherDetail$Payment(o, g, f);
      g.live(o, 'tk_no');
      break;
    case 'Download':
      g._key = result[0].Value;
      break;
&ScriptTaxGridDetailResponse;
    default:
      break;
  }
}
&ScriptTaxGridDetailFunction;
/* <flatten type="Javascript"> */
function set$GridVoucherDetail$Payment(o, g, f) {
  var c = g._getItemValue(o.row, g._getColumnOrder('ma_nt_i'));
  if (c == f.getItemValue('ma_nt')) g.executeExpression(o, [g.$a.tt_nt]);
    else {
      if (c == f._baseCurrency) g.executeExpression(o, [g.$a.tt]);
        else g.executeExpression(o, [g.$a.tt_qd]);
    }
}
function onFocus$GridVoucherDetail$InvoiceNumber(o) {
  var g = $find(o.id.split('_inputCell_')[0]);
  g._enter(o);
  var f = g.get_element().parentForm;
  if (f._action == 'New' || f._action == 'Edit') o._controlBehavior.add_loading(on$Filter$Before$Loading);
}
function on$Filter$Before$Loading(sender, e) {
  var g = sender._element.grid, f = g.get_element().parentForm;
  a = [
    {Name: 'ma_dvcs', Type: 'String', Value: f.getItemValue('ma_dvcs')},
    {Name: 'stt_rec', Type: 'String', Value: f.getItemValue('stt_rec')},
    {Name: 'ma_kh', Type: 'String', Value: f.getItemValue('ma_kh')},
    {Name: 'ngay_lct', Type: 'DateTime', Value: f.getItemValue('ngay_lct')}
  ];
  sender.set_memvars(a);
}
/* </flatten> */
      &DowloadScript;
      &ScriptEmptyExternalField;

grid.response:
&XMLTaxGridDetailResponse;
&CheckRelativeDeclare; select @$relController = 'CDInvoiceLookup', @$relType = 'Lookup', @$relParent = '' &CheckRelativeCall; declare @unitCode varchar(32), @voucherNumber varchar(32), @payID varchar(32) select @unitCode = case when @$ma_dvcs = '' then @@unit else @$ma_dvcs end, @voucherNumber = dbo.ff_PadL(@so_hd, col_length('cttt30', 'so_ct')) if exists(select 1 from cttt30 where ma_dvcs = @unitCode and ma_kh = @$ma_kh and ngay_ct <= @$ngay_lct and loai_tt = 0 and stt_rec = @stt_rec_tt and so_ct = @voucherNumber) select @payID = @stt_rec_tt else select top 1 @payID = stt_rec from cttt30 where ma_dvcs = @unitCode and ma_kh = @$ma_kh and ngay_ct <= @$ngay_lct and loai_tt = 0 and (tat_toan = 0 or (stt_rec in (select stt_rec_tt from cttt30 where stt_rec = @$stt_rec and loai_tt = 1))) and so_ct = @voucherNumber order by stt_rec if @payID is not null begin declare @c numeric(22, 4) select @c = sum(tt_qd) from cttt30 where stt_rec = @$stt_rec and stt_rec_tt = @payID select rtrim(a.tk) as tk, b.ten_tk%l as ten_tk, a.ngay_ct, case when isnull(a.ma_nt, '') = '' then (select val from options where name = 'm_ma_nt0') else a.ma_nt end as ma_nt, a.ty_gia, case when a.ma_nt = '' then a.t_tt else a.t_tt_nt end as tien_hd_nt, a.t_tt_qd - isnull(@c, 0) as da_tt_nt, case when a.ma_nt = '' then a.t_tt else a.t_tt_nt end - (a.t_tt_qd - isnull(@c, 0)) as cl_nt, rtrim(ma_vv) as ma_vv, rtrim(ma_bp) as ma_bp, rtrim(so_lsx) as so_lsx, rtrim(ma_sp) as ma_sp, rtrim(ma_hd) as ma_hd, rtrim(ma_phi) as ma_phi, rtrim(ma_ku) as ma_ku from cttt30 a left join dmtk b on a.tk = b.tk where a.stt_rec = @payID return end
&CreateTicket; select @ticket as value return
